using System.Text.Json;using OpenMarketplace.Shared.Api;namespace OpenMarketplace.Api.Middleware;public sealed class GlobalExceptionMiddleware(RequestDelegate next,ILogger<GlobalExceptionMiddleware> logger){public async Task InvokeAsync(HttpContext context){try{await next(context);}catch(Exception ex){logger.LogError(ex,"Unhandled exception");context.Response.StatusCode=500;context.Response.ContentType="application/json";await context.Response.WriteAsync(JsonSerializer.Serialize(ApiResponse<object>.Fail("INTERNAL_SERVER_ERROR","An unexpected error occurred.",context.TraceIdentifier)));}}}
